// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build IN clause placeholders for usernames
	inPlaceholders := make([]string, len(usernames))
	for i := range inPlaceholders {
		inPlaceholders[i] = "?"
	}
	inClause := "(" + strings.Join(inPlaceholders, ", ") + ")"

	// Base SQL query
	sql := `
	SELECT u.display_name, a.action_type,
	       COUNT(*) as total_actions,
	       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
	       AVG(a.duration_ms) as avg_duration
	FROM user_activity a
	JOIN user_profile u ON a.user_id = u.id
	WHERE u.username IN ` + inClause + `
	AND a.created_at BETWEEN ? AND ?`

	// Add action type filter if specified
	params := make([]interface{}, 0, len(usernames)+2)
	for _, un := range usernames {
		params = append(params, un)
	}
	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	// Add grouping clause
	sql += " GROUP BY u.display_name, a.action_type"

	// Execute query and map results
	var summaries []UserActivitySummary
	_, err := o.Raw(sql, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate group by field
	allowedGroupFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedGroupFields[groupByField] {
		return nil, fmt.Errorf("invalid group by field: %s. Must be one of 'department', 'role', 'display_name'", groupByField)
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build IN clause placeholders for departments
	inPlaceholders := make([]string, len(departments))
	for i := range inPlaceholders {
		inPlaceholders[i] = "?"
	}
	inClause := "(" + strings.Join(inPlaceholders, ", ") + ")"

	// Build SQL query with dynamic group by field
	sql := fmt.Sprintf(`
	SELECT u.%s as group_value,
	       COUNT(DISTINCT u.id) as user_count,
	       COUNT(a.id) as total_activities
	FROM user_profile u
	LEFT JOIN user_activity a ON u.id = a.user_id
	WHERE u.department IN %s
	GROUP BY u.%s`, groupByField, inClause, groupByField)

	// Convert departments to interface slice for query parameters
	params := make([]interface{}, len(departments))
	for i, d := range departments {
		params[i] = d
	}

	// Define struct to hold query results
	type DeptReportRow struct {
		GroupValue      string `orm:"column(group_value)"`
		UserCount       int64  `orm:"column(user_count)"`
		TotalActivities int64  `orm:"column(total_activities)"`
	}

	var reportRows []DeptReportRow
	_, err := o.Raw(sql, params...).QueryRows(&reportRows)
	if err != nil {
		return nil, err
	}

	// Convert struct rows to the required map format
	var result []map[string]interface{}
	for _, row := range reportRows {
		result = append(result, map[string]interface{}{
			"group_value":      row.GroupValue,
			"user_count":       row.UserCount,
			"total_activities": row.TotalActivities,
		})
	}

	return result, nil
}

