	_, err := o.Raw(sql, args...).Values(&rows)
	if err != nil {
		return nil, err
	}

	output := make([]map[string]interface{}, len(rows))
	for i, row := range rows {
		output[i] = map[string]interface{}(row)
	}

	return output, nil
}

