COUNT(DISTINCT u.id) as user_count,
COUNT(a.id) as total_activities
FROM user_profile u
LEFT JOIN user_activity a ON u.id = a.user_id
WHERE u.department IN (%s)
GROUP BY %s`, groupByField, placeholders, groupByField)

	params := make([]interface{}, len(departments))
	for i, dep := range departments {
		params[i] = dep
	}

	var values []orm.Params
	_, err := o.Raw(sql, params...).Values(&values)
	if err != nil {
		return nil, err
	}

	var reports []map[string]interface{}
	for _, v := range values {
		groupValue := v["group_value"].(string)
		userCount := int(v["user_count"].(int64))
		totalActivities := int(v["total_activities"].(int64))

		report := map[string]interface{}{
			"group_value":      groupValue,
			"user_count":       userCount,
			"total_activities": totalActivities,
		}
		reports = append(reports, report)
	}

	return reports, nil
}

